// HasItemSession applies the HasEdge predicate on the "item_session" edge.
func HasItemSession() predicate.ReviewVerdict {
	return predicate.ReviewVerdict(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2O, true, ItemSessionTable, ItemSessionColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasItemSessionWith applies the HasEdge predicate on the "item_session" edge with a given conditions (other predicates).
func HasItemSessionWith(preds ...predicate.ItemSession) predicate.ReviewVerdict {
	return predicate.ReviewVerdict(func(s *sql.Selector) {
		step := newItemSessionStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ReviewVerdict) predicate.ReviewVerdict {
	return predicate.ReviewVerdict(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ReviewVerdict) predicate.ReviewVerdict {
	return predicate.ReviewVerdict(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ReviewVerdict) predicate.ReviewVerdict {
	return predicate.ReviewVerdict(sql.NotPredicates(p))
}
